// Integration test for REST API endpoint
describe('User API Integration', () => {
  let testServer;

  beforeAll(async () => {
    // Start real API server
    testServer = await startAPIServer();
  });

  afterAll(async () => {
    await testServer.close();
  });

  test('POST /users creates and retrieves user', async () => {
    // Create user
    const createResponse = await testServer.post('/users')
      .send({ name: 'Alice', email: 'alice@example.com' });

    expect(createResponse.status).toBe(201);
    const userId = createResponse.data.id;

    // Retrieve user
    const getResponse = await testServer.get(`/users/${userId}`);

    expect(getResponse.status).toBe(200);
    expect(getResponse.data.name).toBe('Alice');
    expect(getResponse.data.email).toBe('alice@example.com');
  });
});
